// ============ DB row -> TypeScript type mappers ============

function dbRowToRecipe(row: any): Recipe {
  return {
    id: row.id,
    title: row.title,
    image: row.image ?? undefined,
    category: row.category,
    categoryId: row.category_id,
    baseServings: row.base_servings,
    ingredients: row.ingredients ?? [],
    steps: row.steps ?? [],
    // 优先读新列，不存在时从 tags 或 category 回退
    structureTag: row.structure_tag ?? row.tags?.[0] ?? row.category ?? '荤菜',
    techniqueTags: row.technique_tags ?? [],
    mainIngredient: row.main_ingredient ?? [],
    difficultyLevel: row.difficulty_level ?? '入门',
    sourceType: row.source_type,
    sourceSnapshot: row.source_snapshot ?? undefined,
    note: row.note ?? undefined,
    favorited: row.favorited ?? false,
    createdAt: row.created_at,
    updatedAt: row.updated_at,
  };
}

function dbRowToTodo(row: any): TodoItem {
  return {
    id: row.id,
    recipeId: row.recipe_id,
    addedAt: row.added_at,
    isCompleted: row.is_completed,
    completedAt: row.completed_at ?? undefined,
  };
}

function dbRowToFoodItem(row: any): FoodItem {
  return {
    id: row.id,
    name: row.name,
    nutritionPer100g: row.nutrition_per_100g,
    source: row.source,
  };
}

function dbRowToUnitConversion(row: any): UnitConversion {
  return {
    id: row.id,
    foodItemId: row.food_item_id ?? undefined,
    unit: row.unit,
    gramsEquivalent: row.grams_equivalent,
  };
}

function dbRowToReviewItem(row: any): ReviewItem {
  return {
    id: row.id,
    parsedData: row.parsed_data,
    sourceType: row.source_type,
    sourceSnapshot: row.source_snapshot ?? undefined,
    confidence: row.confidence ?? {},
    createdAt: row.created_at,
  };
}

// ============ Merge helpers ============

function mergeById<T extends { id: string; updatedAt?: number; createdAt?: number }>(
  local: T[],
  remote: T[]
): T[] {
  const map = new Map<string, T>();
  for (const item of local) {
    map.set(item.id, item);
  }
  for (const item of remote) {
    const existing = map.get(item.id);
    if (!existing) {
      map.set(item.id, item);
    } else {
      const localTime = existing.updatedAt ?? existing.createdAt ?? 0;
      const remoteTime = item.updatedAt ?? item.createdAt ?? 0;
      if (remoteTime > localTime) {
        const merged: T = { ...item };
        const existingObj = existing as any;
        const itemObj = item as any;
        if ('image' in existingObj && 'image' in merged && existingObj.image && !itemObj.image) {
          (merged as any).image = existingObj.image;
        }
        if ('steps' in existingObj && 'steps' in merged && existingObj.steps) {
          (merged as any).steps = existingObj.steps.map((step: any, index: number) => ({
            ...(itemObj.steps?.[index] || {}),
            image: step.image ?? (itemObj.steps?.[index]?.image ?? undefined),
          }));
        }
        map.set(item.id, merged);
      }
    }
  }
  return Array.from(map.values());
}
